#!/usr/bin/env python3
"""One-shot, fail-closed bootstrap for signed Scale OS control-plane v1."""
from __future__ import annotations

import base64
import gzip
import hashlib
import json
from pathlib import Path
import subprocess

PAYLOAD = """"""
EXPECTED = {
    "sovereign-omega-v2/src/consensus/crypto.ts": "9af5723bb1f9125a2cb5e8fd09616bf2aaef7191fcdebf4d52ce74089eabd74e",
    "sovereign-omega-v2/src/scale-os/control-plane.ts": "8257da09958af99b11fffc0f270d1eac1c87c2e128eb4cb72ac430430576cf1e",
    "sovereign-omega-v2/test/unit/scale-os-control-plane.test.ts": "186a99c5c1f45267b7a20842c6af80680ecb6bb9e1d287fb90199b1234f89d09",
    "supabase/migrations/20260719033000_scale_os_control_plane_v1.sql": "e0c8f5ff337cd1c9bab1a45b3934c35c4f8fcec3265934915ea373dad566fe73",
    ".aegis/experiments/scale-os-signed-control-plane-v1.json": "13da5c8a3e1498d8f6a411ce9c3503c36f8e3d28cf93e634a85e324e0bcf270b",
}
OVERWRITE_BLOBS = {
    "sovereign-omega-v2/src/consensus/crypto.ts": "c755578c71332fb3a384473558990f1c27bea13c",
}


def git_blob(path: str) -> str:
    return subprocess.check_output(["git", "hash-object", path], text=True).strip()


def main() -> int:
    files = json.loads(gzip.decompress(base64.b64decode(PAYLOAD)))
    if set(files) != set(EXPECTED):
        raise SystemExit("bootstrap payload path set mismatch")
    for path, content in files.items():
        digest = hashlib.sha256(content.encode()).hexdigest()
        if digest != EXPECTED[path]:
            raise SystemExit(f"bootstrap digest mismatch for {path}")
        target = Path(path)
        if path in OVERWRITE_BLOBS:
            if not target.exists() or git_blob(path) != OVERWRITE_BLOBS[path]:
                raise SystemExit(f"refusing stale overwrite for {path}")
        elif target.exists():
            raise SystemExit(f"refusing to overwrite existing path {path}")
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content, encoding="utf-8")
    print(f"materialized {len(files)} signed Scale OS files")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
